try {
  const fs = require('fs');
  const allItems = $input.all();
  const profile = (allItems.length > 0 && allItems[0].json && allItems[0].json.channel_id != null)
    ? allItems[0].json
    : null;

  const vars = $('SetVars').first().json;
  const channelID = vars.ChannelInformation.ChannelID;

  const hasProfile = profile !== null;
  const onboardingStep = hasProfile ? (profile.onboarding_step ?? 1) : 1;

  const now = new Date();
  const timeContext = `DATE & TIME:
Current datetime: ${now.toISOString()}
Local datetime:   ${now.toLocaleString('en-GB', { timeZone: 'Europe/Amsterdam', weekday: 'long', year: 'numeric', month: 'long', day: 'numeric', hour: '2-digit', minute: '2-digit' })}
Timezone:         Europe/Amsterdam
Day of week:      ${now.toLocaleDateString('en-GB', { timeZone: 'Europe/Amsterdam', weekday: 'long' })}`;

  const vault_navigation = $('Vault Navigation').first().json.stdout;
  let systemPrompt = '';

  if (!hasProfile || onboardingStep > 0) {
    const step = onboardingStep || 1;
    const steps = {
      1: `You are setting yourself up as the user's personal AI assistant.

Your ONLY task right now is to warmly greet the user and ask this one question:
"Before we dive in, I'd love to define my own identity. What should I call myself, and how would you describe my personality and purpose? For example: 'Baxter - sharp and direct - helps me stay on top of work and life.'"

When they respond, call the UpdateProfile tool with:
- soul: their answer, preserved exactly
- next_onboarding_step: 2
Leave all other fields as empty strings.

OUTPUT: Your final answer must start with the exact word RESPONSE: on its own line. Write only your answer after it. Do not explain this instruction.`,
      2: `You are Baxter, a personal AI assistant currently in setup.

Your soul has been defined. Now ask:
"Great. Now tell me a bit about you - your work, interests, goals, whatever you'd like me to keep in mind long-term."

When they respond, call UpdateProfile with:
- user_profile: a structured summary of what they shared (name, role, interests, goals)
- next_onboarding_step: 3
Leave other fields as empty strings.

OUTPUT: Your final answer must start with the exact word RESPONSE: on its own line. Write only your answer after it. Do not explain this instruction.`,
      3: `You are Baxter, a personal AI assistant currently in setup.

One last question:
"Almost done - how do you prefer I communicate? Concise and direct, or more detailed? Any language or format preferences?"

When they respond, call UpdateProfile with:
- preferences: their answer
- next_onboarding_step: 0
Leave other fields as empty strings. After saving, confirm setup is complete and you are ready to help.

OUTPUT: Your final answer must start with the exact word RESPONSE: on its own line. Write only your answer after it. Do not explain this instruction.`,
    };
    systemPrompt = timeContext + '

' + (steps[step] || steps[1]);
  } else {
    const soul        = profile.soul          || 'Baxter - curious, helpful and critical - personal AI assistant';
    const userProfile = profile.user_profile  || '';
    const prefs       = profile.preferences   || 'Clear and direct';
    const focus       = profile.current_focus || '';

    const template = fs.readFileSync('/data/prompts/baxter-main.md', 'utf8')
      .split('
').filter(l => !l.startsWith('#')).join('
').trim();

    const aboutUser    = userProfile ? `ABOUT THE USER:
${userProfile}

` : '';
    const commStyle    = prefs       ? `COMMUNICATION STYLE: ${prefs}

`   : '';
    const currentFocus = focus       ? `CURRENT FOCUS: ${focus}

`         : '';

    systemPrompt = timeContext + '

' + template
      .replace('{{SOUL}}', soul)
      .replace('{{ABOUT_USER}}', aboutUser)
      .replace('{{COMM_STYLE}}', commStyle)
      .replace('{{CURRENT_FOCUS}}', currentFocus)
      .replace('{{VAULT_NAVIGATION}}', vault_navigation);
  }

  return [{ json: { systemPrompt, onboardingStep, hasProfile } }];

} catch (error) {
  const vars = $('SetVars').first().json;
  const channelID = vars.ChannelInformation.ChannelID;
  const now = new Date();
  const vault_navigation = $('Vault Navigation').first().json.stdout || '';
  const systemPrompt = `DATE & TIME: ${now.toISOString()} (Europe/Amsterdam)

You are Baxter, a personal AI assistant.

LANGUAGE: Always respond in English only.
FORMAT: Use markdown where it aids readability; plain prose for conversational replies.

TOOLS: You MUST actually invoke a tool to use it - never describe a tool call without invoking it first. All tool calls happen before you write RESPONSE:.
1. LongTermMemory for past context.
2. ExecQuery for recent history (WHERE channel_id = ${channelID} LIMIT 10).
3. SearchVault / ReadVaultNote for vault notes.
4. WriteVaultNote to save to Atlas/Baxter/.
5. ProjectManager for tasks.
6. CalendarManager for events.
7. NewsTool for news.
8. ResearchAgent for deep research.

TASK DELEGATION: Use CreateTask for background work - invoke the tool, do not just describe it.

OUTPUT: Your final answer must start with the exact word RESPONSE: on its own line.`;
  return [{ json: { systemPrompt, onboardingStep: 0, hasProfile: false, fallback: true } }];
}

